form:Form.form:Scripts:
		var nSQL;
var np;
function onLoad()
{ 
	//alert(Ctrl("hidOICarpeta").GetXValue()); 

	//Recupera datos comunes a todos los modos
	var xmlParam = new NomadXML("PARAMS");
	xmlParam.SetAttr("oi_carpeta",Ctrl("hidOICarpeta").GetXValue());       
	np = new NomadProxy("", ut);
	nSQL = np.SQLService();
	var estado = nSQL.GetOBJ(Ctrl("main").getResource("QRY_ULT_ESTADO"), xmlParam.ToString());  
	Ctrl("oi_est_car_ant").SetXValue(estado.oi_estado_carpeta);	      	 

	if(Ctrl('main').GetMode()=='BAJA')
	{
			//Busca el estado Baja y lo setea al combo
			var oiBaja = nSQL.GetOBJ(Ctrl("main").getResource("Get_oi_Baja"), '');		
			Ctrl('oi_estado_carpeta').SetXValue(oiBaja.oi);
	}

	if(Ctrl('main').GetMode()=='REAPERTURA')
	{
			//Busca el estado Reapertura y lo setea al combo
			var oiRep = nSQL.GetOBJ(Ctrl("main").getResource("Get_oi_Reapertura"), '');		
			Ctrl('oi_estado_carpeta').SetXValue(oiRep.oi);
	} 

	var tipo_carpeta = nSQL.GetOBJ(Ctrl("main").getResource("QRY_ULT_TIPO"), xmlParam.ToString());  
	Ctrl("hid_oi_tipo_carpeta").SetXValue(tipo_carpeta.oi_tipo_carpeta);	

}    

function Aceptar()
{
	if (Ctrl("oi_est_car_ant").GetXValue() == Ctrl("oi_estado_carpeta").GetXValue())
	{
		alert("Está intentando realizar un cambio al mismo estado de carpeta");
		return false;
	}           
	else
	{
		return true;
	}
}
